INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WV-S1536LUX', '2MP 屋外ハウジング一体型AIネットワークカメラ', 'PoE 受電方式 DC12V, 3.1倍電動バリフォーカルレンズ, レンズ交換不可, アダプターボックス同梱, ネットワークカメラ内で高度な映像分析・解析を実現するAIプロセッサーを標準搭載, 圧縮方式H.265対応とAIを活用した圧縮技術, 前面カバーにアドバンスド親水コーティングを施し、降雨時の視認性や防汚性を向上, 赤外線照明(IR-LED)を搭載 (照射距離:50m), カメラ本体でSDメモリーカードに録画可能', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=WV-S1536LUX', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WV-S65340-Z4N', '2MP 屋外ハウジング一体型ネットワークカメラ PTZタイプ', 'PoE+受電方式 AC24V, 光学40倍ズームレンズ, クリアドームカバー, 取付金具別売, レンズ交換不可, ネットワークカメラ内で高度な映像分析・解析を実現するAIプロセッサーを標準搭載, 光学40倍ズームレンズと回転機構により、広いエリアを効率よく監視可能なパンチルトズームタイプ, 水平回転速度: 300°/秒で360°エンドレスに回転, パン・チルト速度:最大500°/秒、パンチルト駆動耐久性: 370万回, 最大256ヵ所のプリセットポジションを記憶, 圧縮方式H.265対応と独自技術: スマートコーディングで従来より配信量・録画容量を大幅削減, フルHD (1920×1080) 画質で最大60枚/秒の映像配信が可能, IP67/IP666 (IEC 60529/JIS C 0920)に準拠した優れた防水防塵性能で、屋外にそのまま取付可能, ドームカバーに親水コーティングを施し、降雨時の視認性や防汚性を向上, カメラ本体でSDメモリーカードに録画可能', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=WV-S65340-Z4N', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
