INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'WV-S1536LNS', '2MP 屋外ハウジング一体型ネットワークカメラ', 'PoE 受電方式 DC12V, 3.6倍電動バリフォーカルレンズ, カメラ取付台付属, レンズ交換不可, アダプターボックス同梱, 潮風などによる腐食に強い耐重塩害カメラと取付金具(国際規格 ISO 14993準拠), 外海に面した地域や沖縄、離島などの重塩害地域にも設置可能, 素材に耐食処理を施し、さらに耐食性の高い塗料を膜厚100 µm以上に上塗り, 塗装方法も角部分も十分な膜厚を確保できる粉体塗装を採用。ねじにも特殊処理を施し腐食による固着を低減', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=WV-S1536LNS', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
