INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = 'パナソニック' LIMIT 1), 'DNH3311', 'EV・PHEV充電用 充電器 ELSEEV hekia S Mode3', 'タイプ:標準タイプ(鍵付き)。コネクタホルダ付属。3kW。ケーブル長:5m。防水保護等級:JIS C 0920 IP55 相当 (充電用コネクタ部除く)。取付対象Dポール: DDP661、DDP662、DDP761、DDP762、DDP660S(別売交換プレート DDP961S)。3kW充電時には20A、4.8kW充電時には30A、6kW充電時には40Aの定格のブレーカが必要。配線設計や現在の電源容量の余裕状況により、電力契約の見直しが必要。EV PHEV充電回路対応コンパクト漏電ブレーカ (BSHE34023, 定格電流40A 感度電流15mA)。', 182000, 'https://dummyimage.com/200x200/cccccc/000.png&text=DNH3311', 'https://drive.google.com/file/d/1ScOmTKi-iTYsCucGvjF_i0nLws9cqVhz/view?usp=drive_link', NULL, NULL, NULL);
